import { Button, H1, H2, Stack, Text, useCanvasState } from "cursor/canvas";
import type { ReactElement } from "react";

const PHOTOS = {"hero":"data:image/jpeg;base64,","qr":"data:image/jpeg;base64,","room":"data:image/jpeg;base64,","balance":"data:image/jpeg;base64,"} as const;

type Theme = {
  id: string;
  name: string;
  accent: string;
  accentSoft: string;
  wash: string;
};

const THEMES: Theme[] = [
  { id: "sky", name: "Небесная гавань", accent: "#007AFF", accentSoft: "#E8F2FF", wash: "rgba(0,122,255,0.18)" },
  { id: "forest", name: "Лесная поляна", accent: "#30B0C7", accentSoft: "#E8F6F8", wash: "rgba(48,176,199,0.18)" },
  { id: "moon", name: "Месечный день", accent: "#BF5AF2", accentSoft: "#F5E8FC", wash: "rgba(191,90,242,0.18)" },
  { id: "sea", name: "Морской бриз", accent: "#32ADE6", accentSoft: "#E8F5FC", wash: "rgba(50,173,230,0.18)" },
  { id: "honey", name: "Мёд и молоко", accent: "#FF9500", accentSoft: "#FFF4E5", wash: "rgba(255,149,0,0.18)" },
  { id: "pony", name: "Пониебов", accent: "#5E5CE6", accentSoft: "#EDEDFC", wash: "rgba(94,92,230,0.18)" },
];

const apple = '-apple-system, BlinkMacSystemFont, "SF Pro Display", sans-serif';
const base = { bg: "#F5F5F7", surface: "#FFFFFF", border: "#E5E5EA", text: "#1D1D1F", muted: "#86868B", ok: "#34C759", reward: "#FF9F0A", bad: "#FF3B30" };

function Img({ src, h, r = 0, wash }: { src: string; h: number; r?: number; wash?: string }) {
  return (
    <div style={{ position: "relative", height: h, borderRadius: r, overflow: "hidden" }}>
      <img src={src} alt="" style={{ width: "100%", height: "100%", objectFit: "cover", display: "block" }} />
      {wash ? <div style={{ position: "absolute", inset: 0, background: wash }} /> : null}
    </div>
  );
}

function Btn({ t, theme, v = "p", sm }: { t: string; theme: Theme; v?: "p" | "s" | "g"; sm?: boolean }) {
  const s = v === "p" ? { bg: theme.accent, c: "#fff", b: "none" } : v === "s" ? { bg: theme.accentSoft, c: theme.accent, b: "none" } : { bg: "transparent", c: theme.accent, b: `1px solid ${base.border}` };
  return (
    <div style={{ height: sm ? 44 : 52, borderRadius: sm ? 22 : 26, background: s.bg, border: s.b, color: s.c, display: "flex", alignItems: "center", justifyContent: "center", fontFamily: apple, fontSize: sm ? 14 : 16, fontWeight: 600 }}>
      {t}
    </div>
  );
}

function Field({ l, v, theme }: { l: string; v: string; theme: Theme }) {
  return (
    <div>
      <div style={{ fontFamily: apple, fontSize: 11, color: base.muted, marginBottom: 6 }}>{l}</div>
      <div style={{ height: 48, borderRadius: 14, background: base.bg, border: `1px solid ${base.border}`, padding: "0 16px", display: "flex", alignItems: "center", fontFamily: apple, fontSize: 15, color: base.text }}>{v}</div>
    </div>
  );
}

function Pill({ t }: { t: string }) {
  return <span style={{ padding: "4px 10px", borderRadius: 999, background: "rgba(255,159,10,0.14)", color: base.reward, fontFamily: apple, fontSize: 11, fontWeight: 700 }}>{t}</span>;
}

function Phone({ theme, title, children }: { theme: Theme; title: string; children: ReactElement }) {
  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 8, alignItems: "center" }}>
      <div style={{ fontFamily: apple, fontSize: 12, fontWeight: 600, color: base.text }}>{title}</div>
      <div style={{ width: 300, borderRadius: 52, border: "3px solid #1D1D1F", background: "#1D1D1F", padding: 11 }}>
        <div style={{ borderRadius: 42, background: base.bg, minHeight: 580, overflow: "hidden", display: "flex", flexDirection: "column" }}>
          <div style={{ height: 46, display: "flex", alignItems: "center", justifyContent: "center", position: "relative" }}>
            <div style={{ width: 108, height: 30, borderRadius: 18, background: "#000" }} />
            <div style={{ position: "absolute", right: 20, top: 14, fontFamily: apple, fontSize: 12, fontWeight: 600 }}>9:41</div>
          </div>
          <div style={{ flex: 1, padding: 18, display: "flex", flexDirection: "column", gap: 14 }}>{children}</div>
          <div style={{ height: 24, display: "flex", alignItems: "center", justifyContent: "center", paddingBottom: 8 }}>
            <div style={{ width: 128, height: 4, borderRadius: 2, background: base.border }} />
          </div>
        </div>
      </div>
    </div>
  );
}

function Hero({ src, title, sub, theme }: { src: string; title: string; sub: string; theme: Theme }) {
  return (
    <div style={{ margin: "-18px -18px 0" }}>
      <Img src={src} h={170} wash={theme.wash} />
      <div style={{ marginTop: -70, padding: "0 18px 18px", position: "relative" }}>
        <div style={{ fontFamily: apple, fontSize: 26, fontWeight: 700, color: "#fff", letterSpacing: -0.5, textShadow: "0 1px 8px rgba(0,0,0,0.35)" }}>{title}</div>
        <div style={{ fontFamily: apple, fontSize: 13, color: "rgba(255,255,255,0.92)", marginTop: 4 }}>{sub}</div>
      </div>
    </div>
  );
}

