        <div style={{ position: "absolute", left: 0, right: 0, bottom: 0, padding: 14, background: "rgba(0,0,0,0.45)", color: "#fff", textAlign: "center", fontFamily: apple, fontSize: 13, fontWeight: 600 }}>Наведи на QR родителя</div>
