const SCREENS = [
  { id: "s1", t: "1 · Привет", C: S1 },
  { id: "s2", t: "2 · Регистрация", C: S2 },
  { id: "s3", t: "3 · QR", C: S3 },
  { id: "s4", t: "4 · Скан", C: S4 },
  { id: "s5", t: "5 · Задача", C: S5 },
  { id: "s6", t: "6 · Ребёнок", C: S6 },
  { id: "s7", t: "7 · Одобрение", C: S7 },
  { id: "s8", t: "8 · Баланс", C: S8 },
];

export default function MvpFamilyPremiumMobile() {
  const [themeId, setThemeId] = useCanvasState("fam-theme", "sky");
  const theme = THEMES.find((x) => x.id === themeId) ?? THEMES[0];

  return (
    <Stack gap={24}>
      <Stack gap={6}>
        <H1>Семейный кошелёк · Premium Mobile</H1>
        <Text tone="secondary">Встроенные editorial-фото (base64). Только мобильные экраны. iOS-типографика, Dynamic Island, 6 семейных акцентов.</Text>
      </Stack>

      <Stack gap={10}>
        <H2>Палитра</H2>
        <div style={{ display: "flex", flexWrap: "wrap", gap: 8 }}>
          {THEMES.map((t) => (
            <span key={t.id}><Button variant={themeId === t.id ? "primary" : "ghost"} onClick={() => setThemeId(t.id)}>{t.name}</Button></span>
          ))}
        </div>
      </Stack>

      <Stack gap={32}>
        {SCREENS.map(({ id, t, C }) => (
          <span key={id}>
            <div style={{ display: "flex", justifyContent: "center" }}>
              <Phone theme={theme} title={t}>
                <C theme={theme} />
              </Phone>
            </div>
          </span>
        ))}
      </Stack>
    </Stack>
  );
}
